  1→/**
  2→ * Graceful shutdown manager for sequant run
  3→ *
  4→ * Handles SIGINT/SIGTERM signals and coordinates cleanup tasks
  5→ * when the process is interrupted.
  6→ *
  7→ * @example
  8→ * ```typescript
  9→ * const shutdown = new ShutdownManager();
 10→ *
 11→ * // Register cleanup tasks
 12→ * shutdown.registerCleanup('Save logs', async () => {
 13→ *   await logWriter.finalize();
 14→ * });
 15→ *
 16→ * // Set abort controller for current phase
 17→ * shutdown.setAbortController(abortController);
 18→ *
 19→ * // In finally block
 20→ * shutdown.dispose();
 21→ * ```
 22→ */
 23→
 24→import chalk from "chalk";
 25→
 26→/**
 27→ * Cleanup task with name for user feedback
 28→ */
 29→interface CleanupTask {
 30→  name: string;
 31→  task: () => Promise<void>;
 32→}
 33→
 34→/**
 35→ * Options for ShutdownManager
 36→ */
 37→export interface ShutdownManagerOptions {
 38→  /** Timeout for cleanup tasks in milliseconds (default: 10000) */
 39→  forceExitTimeout?: number;
 40→  /** Custom output function for testing (default: console.log) */
 41→  output?: (message: string) => void;
 42→  /** Custom error output function for testing (default: console.error) */
 43→  errorOutput?: (message: string) => void;
 44→  /** Custom exit function for testing (default: process.exit) */
 45→  exit?: (code: number) => void;
 46→}
 47→
 48→/**
 49→ * Manages graceful shutdown for sequant run
 50→ *
 51→ * Features:
 52→ * - Registers SIGINT/SIGTERM handlers
 53→ * - Manages cleanup tasks (executed in LIFO order)
 54→ * - Integrates with AbortController for phase cancellation
 55→ * - Supports double Ctrl+C for force exit
 56→ * - Has configurable timeout to prevent hanging
 57→ */
 58→export class ShutdownManager {
 59→  private cleanupTasks: CleanupTask[] = [];
 60→  private _isShuttingDown = false;
 61→  /** Active abort controllers — supports concurrent phase execution (#404) */
 62→  private abortControllers = new Set<AbortController>();
 63→  private forceExitTimeout: number;
 64→  private output: (message: string) => void;
 65→  private errorOutput: (message: string) => void;
 66→  private exit: (code: number) => void;
 67→
 68→  // Store bound handlers for removal in dispose()
 69→  private sigintHandler: () => void;
 70→  private sigtermHandler: () => void;
 71→
 72→  constructor(options: ShutdownManagerOptions = {}) {
 73→    this.forceExitTimeout = options.forceExitTimeout ?? 10000;
 74→    this.output = options.output ?? console.log.bind(console);
 75→    this.errorOutput = options.errorOutput ?? console.error.bind(console);
 76→    this.exit = options.exit ?? process.exit.bind(process);
 77→
 78→    // Bind handlers so we can remove them later
 79→    this.sigintHandler = () => this.gracefulShutdown("SIGINT");
 80→    this.sigtermHandler = () => this.gracefulShutdown("SIGTERM");
 81→
 82→    // Register signal handlers
 83→    process.on("SIGINT", this.sigintHandler);
 84→    process.on("SIGTERM", this.sigtermHandler);
 85→  }
 86→
 87→  /**
 88→   * Whether a shutdown is currently in progress
 89→   */
 90→  get isShuttingDown(): boolean {
 91→    return this._isShuttingDown;
 92→  }
 93→
 94→  /**
 95→   * Alias for isShuttingDown (matches proposed API)
 96→   */
 97→  get shuttingDown(): boolean {
 98→    return this._isShuttingDown;
 99→  }
100→
101→  /**
102→   * Register an abort controller for a running phase.
103→   *
104→   * When shutdown is triggered, ALL registered controllers are aborted,
105→   * supporting concurrent phase execution.
106→   */
107→  addAbortController(controller: AbortController): void {
108→    this.abortControllers.add(controller);
109→  }
110→
111→  /**
112→   * Unregister a specific abort controller after a phase completes.
113→   *
114→   * Only removes the given controller — others remain active.
115→   */
116→  removeAbortController(controller: AbortController): void {
117→    this.abortControllers.delete(controller);
118→  }
119→
120→  /**
121→   * @deprecated Use addAbortController/removeAbortController for concurrent safety.
122→   */
123→  setAbortController(controller: AbortController): void {
124→    this.abortControllers.clear();
125→    this.abortControllers.add(controller);
126→  }
127→
128→  /**
129→   * @deprecated Use removeAbortController(controller) instead.
130→   */
131→  clearAbortController(): void {
132→    this.abortControllers.clear();
133→  }
134→
135→  /**
136→   * Register a cleanup task
137→   *
138→   * Tasks are executed in LIFO order (last registered = first executed).
139→   * This allows dependent cleanup to happen in correct order.
140→   *
141→   * @param name - Human-readable name for user feedback
142→   * @param task - Async function to execute during cleanup
143→   */
144→  registerCleanup(name: string, task: () => Promise<void>): void {
145→    this.cleanupTasks.push({ name, task });
146→  }
147→
148→  /**
149→   * Unregister a cleanup task by name
150→   *
151→   * Use this when a resource is cleaned up normally (e.g., worktree
152→   * removed after successful merge).
153→   */
154→  unregisterCleanup(name: string): void {
155→    this.cleanupTasks = this.cleanupTasks.filter((t) => t.name !== name);
156→  }
157→
158→  /**
159→   * Get the number of registered cleanup tasks
160→   */
161→  getCleanupTaskCount(): number {
162→    return this.cleanupTasks.length;
163→  }
164→
165→  /**
166→   * Trigger graceful shutdown
167→   *
168→   * This is called automatically on SIGINT/SIGTERM, but can also
169→   * be called programmatically for testing.
170→   */
171→  async gracefulShutdown(signal: string): Promise<void> {
172→    // Double signal = force exit
173→    if (this._isShuttingDown) {
174→      this.errorOutput(chalk.red("\nForce exiting..."));
175→      this.exit(1);
176→      return;
177→    }
178→
179→    this._isShuttingDown = true;
180→
181→    this.output(
182→      chalk.yellow(`\n⚠️  Received ${signal}, shutting down gracefully...`),
183→    );
184→
185→    // Abort all in-flight phases immediately
186→    if (this.abortControllers.size > 0) {
187→      const count = this.abortControllers.size;
188→      for (const controller of this.abortControllers) {
189→        controller.abort();
190→      }
191→      this.abortControllers.clear();
192→      this.output(
193→        chalk.green(`✓ Aborted ${count} active phase${count > 1 ? "s" : ""}`),
194→      );
195→    }
196→
197→    // Set up force exit timeout
198→    const forceExitTimer = setTimeout(() => {
199→      this.errorOutput(chalk.red("Cleanup timeout, force exiting"));
200→      this.exit(1);
201→    }, this.forceExitTimeout);
202→
203→    // Run cleanup tasks in reverse order (LIFO)
204→    const tasksToRun = [...this.cleanupTasks].reverse();
205→
206→    for (const { name, task } of tasksToRun) {
207→      try {
208→        await task();
209→        this.output(chalk.green(`✓ ${name}`));
210→      } catch (err) {
211→        const message = err instanceof Error ? err.message : String(err);
212→        this.errorOutput(chalk.red(`✗ ${name}: ${message}`));
213→      }
214→    }
215→
216→    clearTimeout(forceExitTimer);
217→
218→    // Print summary
219→    this.output(chalk.yellow("\nInterrupted. Cleanup complete."));
220→
221→    this.exit(0);
222→  }
223→
224→  /**
225→   * Remove signal handlers and clean up
226→   *
227→   * Call this in a finally block to prevent handler accumulation
228→   * across multiple runs in the same process.
229→   */
230→  dispose(): void {
231→    process.removeListener("SIGINT", this.sigintHandler);
232→    process.removeListener("SIGTERM", this.sigtermHandler);
233→    this.cleanupTasks = [];
234→    this.abortControllers.clear();
235→  }
236→}
