238→/**
239→ * Create a shutdown manager with default options
240→ *
241→ * Convenience function for standard usage.
242→ */
243→export function createShutdownManager(
244→  options?: ShutdownManagerOptions,
245→): ShutdownManager {
246→  return new ShutdownManager(options);
247→}
