108→/**
109→ * Check if a worktree exists for a given branch
110→ */
111→function findExistingWorktree(branch: string): string | null {
112→  const result = spawnSync("git", ["worktree", "list", "--porcelain"], {
113→    stdio: "pipe",
114→  });
115→  if (result.status !== 0) return null;
116→
117→  const output = result.stdout.toString();
118→  const lines = output.split("\n");
119→  let currentPath = "";
120→
121→  for (const line of lines) {
122→    if (line.startsWith("worktree ")) {
123→      currentPath = line.substring(9);
124→    } else if (line.startsWith("branch refs/heads/") && line.includes(branch)) {
125→      return currentPath;
126→    }
127→  }
128→  return null;
129→}
