131→/**
132→ * Detect the remote's default branch without a network call when possible.
133→ *
134→ * Resolution order:
135→ * 1. `git symbolic-ref refs/remotes/origin/HEAD` (local, no network)
136→ * 2. `git remote set-head origin --auto` then retry (network call)
137→ * 3. Fallback to "main"
138→ *
139→ * @param verbose - Log which branch was detected
140→ * @returns The detected default branch name (e.g., "main", "master")
141→ * @internal Exported for testing
142→ */
143→export function detectDefaultBranch(verbose: boolean = false): string {
144→  // Try reading the symbolic ref (no network call)
145→  const result = spawnSync(
146→    "git",
147→    ["symbolic-ref", "refs/remotes/origin/HEAD"],
148→    { stdio: "pipe" },
149→  );
150→  if (result.status === 0) {
151→    const branch = result.stdout
152→      .toString()
153→      .trim()
154→      .replace("refs/remotes/origin/", "");
155→    if (verbose) {
156→      console.log(
157→        chalk.gray(`  Detected default branch: ${branch} (from origin/HEAD)`),
158→      );
159→    }
160→    return branch;
161→  }
162→
163→  // If not set, try refreshing it (requires network)
164→  const autoResult = spawnSync(
165→    "git",
166→    ["remote", "set-head", "origin", "--auto"],
167→    { stdio: "pipe" },
168→  );
169→  if (autoResult.status === 0) {
170→    const retry = spawnSync(
171→      "git",
172→      ["symbolic-ref", "refs/remotes/origin/HEAD"],
173→      { stdio: "pipe" },
174→    );
175→    if (retry.status === 0) {
176→      const branch = retry.stdout
177→        .toString()
178→        .trim()
179→        .replace("refs/remotes/origin/", "");
180→      if (verbose) {
181→        console.log(
182→          chalk.gray(
183→            `  Detected default branch: ${branch} (via remote set-head)`,
184→          ),
185→        );
186→      }
187→      return branch;
188→    }
189→  }
190→
191→  // Final fallback
192→  if (verbose) {
193→    console.log(chalk.gray(`  Detected default branch: main (fallback)`));
194→  }
195→  return "main";
196→}
