198→/**
199→ * Check if a worktree is stale (behind the base branch) and should be recreated
200→ *
201→ * @param worktreePath - Path to the worktree
202→ * @param verbose - Enable verbose output
203→ * @param baseBranch - Base branch to compare against (default: "main")
204→ * @returns Freshness check result
205→ */
206→export function checkWorktreeFreshness(
207→  worktreePath: string,
208→  verbose: boolean,
209→  baseBranch: string = "main",
210→): WorktreeFreshnessResult {
211→  const result: WorktreeFreshnessResult = {
212→    isStale: false,
213→    commitsBehind: 0,
214→    hasUncommittedChanges: false,
215→    hasUnpushedCommits: false,
216→  };
217→
218→  const baseRef = `origin/${baseBranch}`;
219→
220→  // Fetch latest base branch to ensure accurate comparison
221→  spawnSync("git", ["-C", worktreePath, "fetch", "origin", baseBranch], {
222→    stdio: "pipe",
223→    timeout: 30000,
224→  });
225→
226→  // Check for uncommitted changes
227→  const statusResult = spawnSync(
228→    "git",
229→    ["-C", worktreePath, "status", "--porcelain"],
230→    { stdio: "pipe" },
231→  );
232→  if (statusResult.status === 0) {
233→    result.hasUncommittedChanges =
234→      statusResult.stdout.toString().trim().length > 0;
235→  }
236→
237→  // Get merge base with the base branch
238→  const mergeBaseResult = spawnSync(
239→    "git",
240→    ["-C", worktreePath, "merge-base", "HEAD", baseRef],
241→    { stdio: "pipe" },
242→  );
243→  if (mergeBaseResult.status !== 0) {
244→    // Can't determine merge base - not stale
245→    return result;
246→  }
247→  const mergeBase = mergeBaseResult.stdout.toString().trim();
248→
249→  // Get base branch HEAD
250→  const baseHeadResult = spawnSync(
251→    "git",
252→    ["-C", worktreePath, "rev-parse", baseRef],
253→    { stdio: "pipe" },
254→  );
255→  if (baseHeadResult.status !== 0) {
256→    return result;
257→  }
258→  const baseHead = baseHeadResult.stdout.toString().trim();
259→
260→  // Count commits behind base branch
261→  if (mergeBase !== baseHead) {
262→    const countResult = spawnSync(
263→      "git",
264→      ["-C", worktreePath, "rev-list", "--count", `${mergeBase}..${baseHead}`],
265→      { stdio: "pipe" },
266→    );
267→    if (countResult.status === 0) {
268→      result.commitsBehind = parseInt(countResult.stdout.toString().trim(), 10);
269→      // Consider stale if more than 5 commits behind (configurable threshold)
270→      result.isStale = result.commitsBehind > 5;
271→    }
272→  }
273→
274→  // Check for unpushed commits (work in progress)
275→  const unpushedResult = spawnSync(
276→    "git",
277→    ["-C", worktreePath, "log", "--oneline", "@{u}..HEAD"],
278→    { stdio: "pipe" },
279→  );
280→  if (unpushedResult.status === 0) {
281→    result.hasUnpushedCommits =
282→      unpushedResult.stdout.toString().trim().length > 0;
283→  }
284→
285→  if (verbose && result.isStale) {
286→    console.log(
287→      chalk.gray(
288→        `    📊 Worktree is ${result.commitsBehind} commits behind origin/${baseBranch}`,
289→      ),
290→    );
291→  }
292→
293→  return result;
294→}
