296→/**
297→ * Remove and recreate a stale worktree
298→ *
299→ * @param existingPath - Path to existing worktree
300→ * @param branch - Branch name
301→ * @param verbose - Enable verbose output
302→ * @returns true if worktree was removed
303→ */
304→export function removeStaleWorktree(
305→  existingPath: string,
306→  branch: string,
307→  verbose: boolean,
308→): boolean {
309→  if (verbose) {
310→    console.log(chalk.gray(`    🗑️  Removing stale worktree...`));
311→  }
312→
313→  // Remove the worktree
314→  const removeResult = spawnSync(
315→    "git",
316→    ["worktree", "remove", "--force", existingPath],
317→    { stdio: "pipe" },
318→  );
319→
320→  if (removeResult.status !== 0) {
321→    const error = removeResult.stderr.toString();
322→    console.log(chalk.yellow(`    ⚠️  Could not remove worktree: ${error}`));
323→    return false;
324→  }
325→
326→  // Delete the branch so it can be recreated fresh
327→  const deleteResult = spawnSync("git", ["branch", "-D", branch], {
328→    stdio: "pipe",
329→  });
