353→  if (result.status !== 0) return [];
354→
355→  const output = result.stdout.toString();
356→  const lines = output.split("\n");
357→  const worktrees: Array<{
358→    path: string;
359→    branch: string;
360→    issue: number | null;
361→  }> = [];
362→
363→  let currentPath = "";
364→  let currentBranch = "";
365→
366→  for (const line of lines) {
367→    if (line.startsWith("worktree ")) {
368→      currentPath = line.substring(9);
369→    } else if (line.startsWith("branch refs/heads/")) {
370→      currentBranch = line.substring(18);
371→      // Extract issue number from branch name (e.g., feature/123-some-title)
372→      const issueMatch = currentBranch.match(/feature\/(\d+)-/);
373→      const issue = issueMatch ? parseInt(issueMatch[1], 10) : null;
374→      worktrees.push({ path: currentPath, branch: currentBranch, issue });
375→      currentPath = "";
376→      currentBranch = "";
377→    }
378→  }
379→
380→  return worktrees;
381→}
