400→/**
401→ * Get diff stats for a worktree (files changed, lines added)
402→ * Returns aggregate metrics only - no file paths to preserve privacy
403→ */
404→export function getWorktreeDiffStats(worktreePath: string): {
405→  filesChanged: number;
406→  linesAdded: number;
407→} {
408→  const result = spawnSync(
409→    "git",
410→    ["-C", worktreePath, "diff", "--stat", "main...HEAD"],
411→    { stdio: "pipe" },
412→  );
413→
414→  if (result.status !== 0) {
415→    return { filesChanged: 0, linesAdded: 0 };
416→  }
417→
418→  const output = result.stdout.toString();
419→  const lines = output.trim().split("\n");
420→
421→  // Summary line is last and looks like: " 5 files changed, 100 insertions(+), 20 deletions(-)"
422→  const summaryLine = lines[lines.length - 1];
423→  if (!summaryLine) {
424→    return { filesChanged: 0, linesAdded: 0 };
425→  }
426→
427→  const filesMatch = summaryLine.match(/(\d+)\s+files?\s+changed/);
428→  const insertionsMatch = summaryLine.match(/(\d+)\s+insertions?\(\+\)/);
429→
430→  return {
431→    filesChanged: filesMatch ? parseInt(filesMatch[1], 10) : 0,
432→    linesAdded: insertionsMatch ? parseInt(insertionsMatch[1], 10) : 0,
433→  };
434→}
